# Check all secrets cluster-wide for CA key material
kubectl get secret -A -o json | python3 -c "
import sys, json, base64
d = json.load(sys.stdin)
for item in d.get('items', []):
    ns = item['metadata']['namespace']
    name = item['metadata']['name']
    for k, v in item.get('data', {}).items():
        try:
            decoded = base64.b64decode(v).decode('utf-8', errors='replace')
            if 'PRIVATE KEY' in decoded:
                print(f'{ns}/{name}/{k}: has private key ({len(decoded)} bytes)')
        except:
            pass
" 2>/dev/null | grep -v "kube-system\|kube-public\|ingress-nginx\|default"
